1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Customer {
11	  yearsWithMHPCO: number;
12	}
13	
14	interface Scenario {
15	  customer: Customer;
16	  steps: QuoteStep[];
17	}
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	
30	const itemPremium = (item: Item): number => {
31	  const base = BASE_PREMIUM[item.type];
32	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
33	};
34	
35	const quotePremium = (step: QuoteStep): number => {
36	  const total = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
37	  return Math.ceil(total) + PROCESSING_FEE;
38	};
39	
40	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
41	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
42	  return { results };
43	};
